noncompliant:
private Color color = new Color("red");
private void DoSomething()
{
    lock (color) // Noncompliant: lock is on non-readonly field
    {
        color = new Color("green"); // Field can be changed, breaking synchronization
        // other operations...
    }
}

private object lockObject = new object();
public void Method1()
{
    lock (lockObject) // Noncompliant: field is not readonly
    {
        lockObject = new object(); // Can be reassigned
    }
}

compliant:
private readonly Color color = new Color("red");
private void DoSomething()
{
    lock (color) // Compliant: field is readonly
    {
        // Operations here are safely synchronized
        // color cannot be reassigned
    }
}

private readonly object lockObject = new object();
public void Method1()
{
    lock (lockObject) // Compliant: readonly field ensures consistent lock object
    {
        // Safe operations
    }
}
